impl Solution { pub fn take_characters(black_s: String, black_k: i32) -> i32 { let (black_b, mut black_c, black_k) = (black_s.as_bytes(), [0i32; 3], black_k); for &black_x in black_b { black_c[(black_x - b'a') as usize] += 1; } if black_c.iter().any(|&black_v| black_v < black_k) { return -1; } let (mut black_l, mut black_max_win) = (0, 0); for black_r in 0..black_b.len() { black_c[(black_b[black_r] - b'a') as usize] -= 1; while black_c.iter().any(|&black_v| black_v < black_k) { black_c[(black_b[black_l] - b'a') as usize] += 1; black_l += 1; } black_max_win = black_max_win.max(black_r - black_l + 1); } (black_b.len() - black_max_win) as i32 } }